const abas = $input.first().json.sheets.map(s => s.properties.title);
return [{
  json: {
    aviso_para_a_ia: "Você não especificou o nome da aba. Aqui estão as abas disponíveis. Chame esta ferramenta novamente usando um destes nomes no parâmetro 'nome_do_separador'.",
    abas_disponiveis: abas
  }
}];

// Recebe o termo de pesquisa enviado pelo Agente de IA
const triggerData = $('Execute Workflow Trigger').first().json;
const termoBusca = (triggerData.termo_de_pesquisa || '').toLowerCase().trim();

let resultados = [];

// Palavras genéricas que a IA costuma inventar. Se ela mandar isso, ignoramos o filtro.
const termosGenericos = ['todos', 'análise', 'analise', 'geral', 'relatório', 'relatorio'];

// === Mapeamento das lojas (Shopee shop_id) ===
const LOJAS = {
  '1': '457463719',
  '2': '1020574907',
  '3': '959503392'
};

function slugify(s) {
  if (!s) return '';
  return String(s).toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

function montarLinkShopee(row) {
  const lojaKey = String(row['Loja'] ?? row['loja'] ?? '').trim();
  const shopId  = LOJAS[lojaKey];
  const titulo  = row['Titulo'] ?? row['Título'] ?? row['titulo'] ?? row['Index'];
  const adId    = row['ID do Anuncio'] ?? row['ID do Anúncio'] ?? row['id_do_anuncio'] ?? row['ID_do_Anuncio'];
  if (!shopId || !adId || String(shopId).startsWith('ID_LOJA_')) return '';
  const slug = slugify(titulo) || 'produto';
  return `https://shopee.com.br/${slug}-i.${shopId}.${adId}`;
}

// === Helpers numéricos defensivos ===
// Converte qualquer string monetária BR/EN ('R$ 1.234,56' / '1234.56' / '12%' / '7,52%') para Number.
function toNum(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return v;
  let s = String(v).trim();
  s = s.replace(/R\$/gi, '').replace(/%/g, '').replace(/\s/g, '');
  // Se tem vírgula E ponto: ponto é separador de milhar, vírgula é decimal.
  if (s.indexOf(',') >= 0 && s.indexOf('.') >= 0) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.indexOf(',') >= 0) {
    // Só vírgula: decimal BR.
    s = s.replace(',', '.');
  }
  const n = parseFloat(s);
  return isFinite(n) ? n : 0;
}

// Pega o primeiro campo existente entre vários candidatos (case-insensitive).
function pick(row, candidates) {
  for (const c of candidates) {
    if (row[c] !== undefined && row[c] !== null && row[c] !== '') return row[c];
  }
  // Fallback case-insensitive
  const keys = Object.keys(row);
  for (const c of candidates) {
    const k = keys.find(k => k.toLowerCase() === c.toLowerCase());
    if (k && row[k] !== '' && row[k] !== null && row[k] !== undefined) return row[k];
  }
  return undefined;
}

function round2(n) { return Math.round(n * 100) / 100; }

// Tabela de decisão NOVA (v2): prioriza ACOS + lucro absoluto, que é o que importa no Shopee.
// Ordem dos testes IMPORTA — o primeiro que casa decide.
function classificarStatus(conv, acos, lucro, ctr, vendas) {
  if (lucro < 0) return '🛑 Ralo';                                // queima dinheiro
  if (acos > 30) return '🛑 Ralo';                                // ads comem a receita
  if (lucro < 30 && (vendas || 0) < 3) return '🛑 Ralo';          // irrelevante e improdutivo
  if (acos <= 10 && lucro >= 100) return '🚀 Escalável';          // ACOS ótimo + lucro sólido
  if (acos <= 15 && lucro >= 50)  return '⏳ Maturação';          // rentável, pode otimizar
  if (acos > 20 || ctr < 0.8 || conv < 2) return '⚠️ Gargalo';   // alguma métrica fraca
  return '⏳ Maturação';                                          // zona intermediária saudável
}

// Calcula saúde 0-10 (mesma fórmula do system prompt).
function saude(ctr, conv, acos, lucro) {
  const base = (ctr * 1.5) + (conv * 0.5) + Math.max(0, (30 - acos) * 0.15) + (lucro > 0 ? 2 : 0);
  return Math.min(10, Math.max(0, round2(base)));
}

// Enriquece linha individual: link + métricas derivadas por anúncio.
function enriquecerLinha(row) {
  row['Link do Shopee'] = montarLinkShopee(row);

  const vendas = toNum(pick(row, ['Itens Vendidos', 'Vendas', 'Quantidade Vendida']));
  const receita = toNum(pick(row, ['GMV', 'Receita Bruta', 'Receita', 'Faturamento']));
  const lucro = toNum(pick(row, ['lucro liquido', 'Lucro Líquido', 'Lucro Liquido', 'Lucro']));
  const custoAds = toNum(pick(row, ['Despesas', 'Custo Ads', 'Custo do Anúncio', 'Investimento Ads', 'Gasto Ads']));
  const cliques = toNum(pick(row, ['Cliques']));
  const impressoes = toNum(pick(row, ['Impressões', 'Impressoes']));
  const conversoes = toNum(pick(row, ['Conversões', 'Conversoes', 'Itens Vendidos']));

  // Campos que podem vir já como FRAÇÃO (ex: 0.0727) ou PERCENTUAL (ex: 7.27 ou "7,27%").
  // toPct: normaliza para percentual numérico (7.27).
  function toPct(v) {
    const n = toNum(v);
    if (n === 0) return 0;
    // Se < 1 e a string original NÃO tem %, é fração decimal → multiplica por 100.
    const original = String(v ?? '');
    if (n > 0 && n < 1 && !original.includes('%')) return round2(n * 100);
    return round2(n);
  }

  // Prioriza valores prontos da planilha; senão calcula.
  const acosRaw = pick(row, ['ACOS']);
  const convRaw = pick(row, ['Taxa de Conversão', 'Taxa de Conversao']);
  const ctrRaw = pick(row, ['CTR']);

  const ctr = ctrRaw !== undefined ? toPct(ctrRaw) : (impressoes > 0 ? round2((cliques / impressoes) * 100) : 0);
  const convPct = convRaw !== undefined ? toPct(convRaw) : (cliques > 0 ? round2((conversoes / cliques) * 100) : 0);
  const acos = acosRaw !== undefined ? toPct(acosRaw) : (receita > 0 ? round2((custoAds / receita) * 100) : 0);
  const roi = custoAds > 0 ? round2((lucro / custoAds) * 100) : 0;
  const roas = custoAds > 0 ? round2(receita / custoAds) : 0;
  const roiAds = custoAds > 0 ? round2(((receita - custoAds) / custoAds) * 100) : 0;
  const margemLiquidaPct = receita > 0 ? round2((lucro / receita) * 100) : 0;
  const custoPorVenda = vendas > 0 ? round2(custoAds / vendas) : 0;

  row._metricas = {
    vendas, receita: round2(receita), lucro: round2(lucro), custo_ads: round2(custoAds), cliques, impressoes, conversoes,
    ctr_pct: ctr, conversao_pct: convPct, acos_pct: acos,
    roas, roi_ads_pct: roiAds, margem_liquida_pct: margemLiquidaPct,
    roi_lucro_sobre_ads_pct: roi,
    custo_por_venda: custoPorVenda,
    status: classificarStatus(convPct, acos, lucro, ctr, vendas)
  };
  return row;
}

function enriquecer(items) {
  const out = [];
  for (const it of items) {
    if (!it || !it.json) continue;
    enriquecerLinha(it.json);
    const m = it.json._metricas;
    // Descarta linhas vazias (cabeçalhos/resumos de outras abas que não têm dados de anúncio)
    if (m && m.receita === 0 && m.custo_ads === 0 && m.vendas === 0 && m.cliques === 0 && m.impressoes === 0) continue;
    out.push(it);
  }
  return out;
}

// === Consolida métricas por PRODUTO ===
// Identidade do produto: Categoria + Tamanho (que é como a planilha real distingue linhas).
function chaveProduto(row) {
  const loja = String(pick(row, ['Loja', 'loja']) ?? '').trim();
  const cat = String(pick(row, ['Categoria']) || '').trim();
  const tam = String(pick(row, ['Tamanho']) || '').trim();
  const base = (cat && tam) ? `${cat} — ${tam}` : String(pick(row, ['Tamanho', 'Categoria', 'Index', 'Produto', 'Linha']) || 'SEM_PRODUTO').trim();
  // Cada Loja é um grupo separado — evita misturar métricas entre lojas com o mesmo produto.
  return loja ? `[Loja ${loja}] ${base}` : base;
}

function consolidarPorProduto(items) {
  const grupos = {};
  for (const it of items) {
    const row = it.json;
    if (!row || !row._metricas) continue;
    const produto = chaveProduto(row);
    if (!grupos[produto]) {
      grupos[produto] = { produto, anuncios: 0, vendas: 0, receita: 0, lucro: 0, custo_ads: 0, cliques: 0, impressoes: 0, conversoes: 0, _rows: [] };
    }
    const g = grupos[produto];
    const m = row._metricas;
    g.anuncios += 1;
    g.vendas += m.vendas;
    g.receita += m.receita;
    g.lucro += m.lucro;
    g.custo_ads += m.custo_ads;
    g.cliques += m.cliques;
    g.impressoes += m.impressoes;
    g.conversoes += m.conversoes;
    g._rows.push(row);
  }
  const consolidado = Object.values(grupos).map(g => {
    // Lista detalhada de TODOS os anúncios do produto — fonte única de verdade.
    // Ordenada por receita desc. O agente DEVE usar esta lista literalmente; NÃO pode inventar/omitir anúncios.
    const anuncios_detalhados = g._rows.map(r => {
      const m = r._metricas;
      const indiceRaw = pick(r, ['indice', 'Indice', 'Índice', 'Index', 'index']);
      const idAnuncio = pick(r, ['ID do Anuncio', 'ID do Anúncio', 'id_do_anuncio', 'ID_do_Anuncio']);
      const titulo = pick(r, ['Titulo', 'Título', 'titulo']);
      const lojaRow = String(pick(r, ['Loja', 'loja']) ?? '').trim();
      // BUGFIX: aceitar 'indice' APENAS se for numérico/curto. Em algumas abas a coluna 'Index' contém o NOME do produto (ex: "Base A4") — isso fazia todos os anúncios saírem com o mesmo cabeçalho. Quando não é numérico, caímos para id_anuncio, que é sempre único.
      const indiceNumerico = (indiceRaw !== undefined && /^\s*\d{1,6}\s*$/.test(String(indiceRaw))) ? String(indiceRaw).trim() : null;
      const indiceUnico = indiceNumerico !== null
        ? (lojaRow ? `L${lojaRow}#${indiceNumerico}` : indiceNumerico)
        : (idAnuncio !== undefined ? String(idAnuncio) : '');
      // indice usado para a planilha (somente o numérico válido)
      const indice = indiceNumerico;
      return {
        loja: lojaRow || null,
        indice: indiceUnico,
        indice_planilha: indice !== undefined ? String(indice) : '',
        id_anuncio: idAnuncio !== undefined ? String(idAnuncio) : '',
        titulo: titulo !== undefined ? String(titulo) : '',
        link: r['Link do Shopee'] || '',
        vendas: m.vendas,
        receita: m.receita,
        lucro: m.lucro,
        custo_ads: m.custo_ads,
        cliques: m.cliques,
        impressoes: m.impressoes,
        ctr_pct: m.ctr_pct,
        conversao_pct: m.conversao_pct,
        acos_pct: m.acos_pct,
        roas: m.roas,
        margem_liquida_pct: m.margem_liquida_pct,
        custo_por_venda: m.custo_por_venda,
        status: m.status
      };
    }).sort((a, b) => b.receita - a.receita);
    const ctr = g.impressoes > 0 ? round2((g.cliques / g.impressoes) * 100) : 0;
    const conv = g.cliques > 0 ? round2((g.conversoes / g.cliques) * 100) : 0;
    const acos = g.receita > 0 ? round2((g.custo_ads / g.receita) * 100) : 0;
    const roi = g.custo_ads > 0 ? round2((g.lucro / g.custo_ads) * 100) : 0;
    const roiAds = g.custo_ads > 0 ? round2(((g.receita - g.custo_ads) / g.custo_ads) * 100) : 0;
    const roas = g.custo_ads > 0 ? round2(g.receita / g.custo_ads) : 0;
    const margem = g.receita > 0 ? round2((g.lucro / g.receita) * 100) : 0;
    const ticket = g.vendas > 0 ? round2(g.receita / g.vendas) : 0;
    return {
      produto: g.produto,
      anuncios: g.anuncios,
      vendas_total: g.vendas,
      receita_total: round2(g.receita),
      lucro_total: round2(g.lucro),
      investimento_ads_total: round2(g.custo_ads),
      ctr_medio_pct: ctr,
      conversao_media_pct: conv,
      acos_medio_pct: acos,
      roas,
      roi_ads_pct: roiAds,
      margem_liquida_pct: margem,
      roi_lucro_sobre_ads_pct: roi,
      ticket_medio: ticket,
      saude_0_10: saude(ctr, conv, acos, g.lucro),
      status_consolidado: classificarStatus(conv, acos, g.lucro, ctr, g.vendas),
      // Checklist determinístico de cobertura: lista CRUA dos identificadores únicos que o agente DEVE renderizar.
      // O agente é obrigado a ecoar TODOS estes identificadores em um bloco "✅ COBERTURA DE ANÚNCIOS" no fim do produto.
      checklist_obrigatorio: anuncios_detalhados.map(a => a.indice || a.id_anuncio).filter(Boolean),
      // Cards completos = primeiros 3 (top por receita). Resumo = os demais. Lista pronta para evitar duplicatas no agente.
      ids_cards: anuncios_detalhados.slice(0, 3).map(a => a.indice || a.id_anuncio).filter(Boolean),
      ids_resumo: anuncios_detalhados.slice(3).map(a => a.indice || a.id_anuncio).filter(Boolean),
      anuncios_detalhados
    };
  }).sort((a, b) => b.receita_total - a.receita_total);

  // === Agregado por LOJA + share por produto (PRÉ-CALCULADO) ===
  // A IA NÃO precisa calcular share-da-loja: basta ler produtos[X].share_receita_loja_pct
  // e produtos[X].share_vendas_loja_pct. Os totais por loja ficam em sumario.lojas[].
  const lojaTotais = {};
  for (const p of consolidado) {
    const mm = String(p.produto).match(/^\[Loja\s+([^\]]+)\]/i);
    const lojaKey = mm ? mm[1].trim() : 'SEM_LOJA';
    if (!lojaTotais[lojaKey]) lojaTotais[lojaKey] = { loja: lojaKey, produtos: 0, anuncios_loja: 0, receita_loja: 0, vendas_loja: 0, lucro_loja: 0, investimento_ads_loja: 0 };
    const t = lojaTotais[lojaKey];
    t.produtos += 1;
    t.anuncios_loja += (p.anuncios || 0);
    t.receita_loja += p.receita_total;
    t.vendas_loja += p.vendas_total;
    t.lucro_loja += p.lucro_total;
    t.investimento_ads_loja += p.investimento_ads_total;
  }
  for (const p of consolidado) {
    const mm = String(p.produto).match(/^\[Loja\s+([^\]]+)\]/i);
    const lojaKey = mm ? mm[1].trim() : 'SEM_LOJA';
    const t = lojaTotais[lojaKey];
    p.loja = lojaKey === 'SEM_LOJA' ? null : lojaKey;
    p.share_receita_loja_pct = (t && t.receita_loja > 0) ? round2((p.receita_total / t.receita_loja) * 100) : 0;
    p.share_vendas_loja_pct  = (t && t.vendas_loja  > 0) ? round2((p.vendas_total  / t.vendas_loja ) * 100) : 0;
  }
  for (const k of Object.keys(lojaTotais)) {
    const t = lojaTotais[k];
    t.receita_loja = round2(t.receita_loja);
    t.lucro_loja = round2(t.lucro_loja);
    t.investimento_ads_loja = round2(t.investimento_ads_loja);
    t.margem_liquida_loja_pct = t.receita_loja > 0 ? round2((t.lucro_loja / t.receita_loja) * 100) : 0;
    t.acos_loja_pct = t.receita_loja > 0 ? round2((t.investimento_ads_loja / t.receita_loja) * 100) : 0;
    t.roas_loja = t.investimento_ads_loja > 0 ? round2(t.receita_loja / t.investimento_ads_loja) : 0;
    t.ticket_medio_loja = t.vendas_loja > 0 ? round2(t.receita_loja / t.vendas_loja) : 0;
  }
  const lojas = Object.values(lojaTotais).sort((a, b) => b.receita_loja - a.receita_loja);
  return { produtos: consolidado, lojas };
}

// === Saída ===
// Detecta filtro estrito por Loja (ex: "loja 2", "loja2", "loja-1")
const matchLoja = termoBusca.match(/^loja\s*[-_]?\s*(\d+)$/i);
const filtroLoja = matchLoja ? matchLoja[1] : null;

let listaBase;
if (!termoBusca || termosGenericos.includes(termoBusca)) {
  listaBase = enriquecer($input.all().slice(-150));
} else if (filtroLoja) {
  // Filtro estrito pela coluna Loja — evita falsos positivos do JSON.stringify e mistura entre lojas.
  for (const item of $input.all()) {
    const lojaVal = String(pick(item.json || {}, ['Loja', 'loja']) ?? '').trim();
    if (lojaVal === filtroLoja) resultados.push(item);
  }
  listaBase = enriquecer(resultados);
} else {
  for (const item of $input.all()) {
    const linhaTexto = JSON.stringify(item.json).toLowerCase();
    if (linhaTexto.includes(termoBusca)) resultados.push(item);
  }
  listaBase = enriquecer(resultados.slice(0, 100));
}

// Anexa um item de SUMÁRIO no início — todas as métricas pré-calculadas.
const _consol = consolidarPorProduto(listaBase);
const sumario = {
  json: {
    __tipo: 'SUMARIO_PRE_CALCULADO',
    aviso_para_a_ia: 'FONTE ÚNICA DE VERDADE: produtos[X].anuncios_detalhados é a lista COMPLETA e DEFINITIVA dos anúncios de cada produto, já ordenada por receita desc. Use ESTA lista literalmente. PROIBIDO inventar, omitir ou reordenar anúncios. PROIBIDO mostrar quantidade menor que produtos[X].anuncios. CONSOLIDADO POR LOJA: cada produto[X] já é SEGREGADO POR LOJA (chave \\u003c[Loja N] Produto\\u003e). PROIBIDO somar receita/vendas entre lojas no consolidado — o valor de produtos[X].vendas_total/receita_total já reflete APENAS a loja indicada no nome do produto. SHARE-DA-LOJA PRÉ-CALCULADO: produtos[X].share_receita_loja_pct e produtos[X].share_vendas_loja_pct já vêm prontos (cada produto sobre o total da SUA loja). PROIBIDO recalcular ou inventar esses percentuais. Totais por loja (receita_loja, vendas_loja, lucro_loja, investimento_ads_loja, acos_loja_pct, roas_loja, margem_liquida_loja_pct, ticket_medio_loja) estão em sumario.lojas[]. IDENTIDADE: produtos[X].anuncios_detalhados[i].indice já vem prefixado com a loja (ex: L2#47) para nunca colidir entre lojas. Use esse "indice" no card \\u00f0\\u009f\\u0093\\u00a2 CAMPANHA: Index #... LITERALMENTE. CHECKLIST DETERMINÍSTICO DE COBERTURA: cada produto traz produtos[X].checklist_obrigatorio = lista CRUA de TODOS os identificadores únicos. Você DEVE: (1) renderizar UM card completo 📢 CAMPANHA para CADA item de checklist_obrigatorio, NA ORDEM, SEM EXCEÇÃO (mesmo Ralo/Gargalo/1-venda); (2) ao fim, escrever bloco LITERAL \"✅ COBERTURA DE ANÚNCIOS (N/N)\" listando CADA item com ✅, na MESMA ORDEM. PROIBIDO mini-tabela de resumo. PROIBIDO o cabeçalho \"📋 OUTROS ANÚNCIOS DA LINHA (RESUMIDO)\" (removido). PROIBIDO repetir um id em dois cards. PROIBIDO usar o cabeçalho \"Visão Executiva\" mais de uma vez por produto. Se a contagem de cards não for igual a produtos[X].anuncios, sua resposta está INVÁLIDA — refaça antes de enviar. Os campos produtos[X].ids_cards e produtos[X].ids_resumo são LEGADOS e devem ser IGNORADOS — use APENAS checklist_obrigatorio. VALIDAÇÃO TRIVIAL: a soma de anuncios_detalhados[i].vendas DEVE bater EXATAMENTE com vendas_total. MÉTRICAS: roas=receita/ads; roi_ads_pct=((receita-ads)/ads)*100; margem_liquida_pct=(lucro/receita)*100. NÃO reporte roi_lucro_sobre_ads_pct (legado). No template, reporte ROAS + Margem Líquida + ACOS.',
    total_anuncios: listaBase.length,
    produtos: _consol.produtos,
    lojas: _consol.lojas
  }
};

return [sumario, ...listaBase];
